const body = $input.first().json.body;
const entity = body.entity_data;

if (body.event !== 'tender.deadline_approaching') return [];

const deadline = entity.deadline_at ? new Date(entity.deadline_at) : null;
const daysLeft = deadline ? Math.ceil((deadline - Date.now()) / 86400000) : '?';

const msg = `⏰ <b>DEADLINE za ${daysLeft} dni!</b>\n\n` +
  `📋 ${entity.title || 'Przetarg'}\n` +
  `🏢 ${entity.buyer || '-'}\n` +
  `📍 ${entity.voivodeship || '-'}\n` +
  `💰 ${entity.value_pln ? Number(entity.value_pln).toLocaleString('pl-PL') + ' PLN' : '-'}\n\n` +
  `Termin: ${deadline ? deadline.toLocaleDateString('pl-PL') : '-'}`;

return [{ json: { chatId: $env.TELEGRAM_CHAT_ID, text: msg } }];
